(window["webpackJsonp"]=window["webpackJsonp"]||[]).push([["learn25"],{"5c9e":function(n,e){n.exports="### NodeJS是什么\n```\nNodeJS是一门非阻塞型语言 并且由事件驱动，类似于Android中的onClickListener()\n\nCPU动作： 计算、逻辑判断\nI/O动作： 存取设备、网络操作、数据库\n```\n### CommonJS\n```\n每个文件是一个模块，有自己的作用域\n在模块内部module变量代表模块本身\nmodule.export属性代表模块对外接口\n```\nrequire规则\n```\n/表示绝对路径，./表示相对于当前文件的\n支持js，json，node拓展名，不写依次尝试\n不写路径则认为是build-in 模块或者各级node_modules内的第三方模块\n```\nrequire特性\n```\nmodule被加载的时候执行，加载后缓存\n一旦出现某个模块被循环加载，就只输出已经执行的部分，还未执行的部分不会输出（尽量避免这种情况）\n```\n引用系统内置模块\n```js\nconst fs = require('fs');\n\nconst result = fs.readFile('./06_fs.js', (err, data) => {\n    if (err) {\n        console.log(err);\n    } else {\n        console.log(data.toString());\n    }\n});\n\nconsole.log(result);\n```\n引用第三方模块\n```js\nconst chalk = require('chalk');\n\nconsole.log(chalk.red('This is red!'));\n```\n注意\n```js\n// 默认会设置一个快捷方式\nconst exports = module.exports;\n// 可以正常拿到test\nexports.test =100\n// 修改了引用的指向，这和module.exports没有任何关系了\nexports = {\n  a:1\n}\n// 这样是ok的\nmodule.exports = {\n  a:1\n}\n```"},d1b1:function(n,e,o){"use strict";o.r(e);var s=function(){var n=this,e=n.$createElement,s=n._self._c||e;return s("markdown",{attrs:{source:o("5c9e")}})},r=[],t=o("2877"),l={},u=Object(t["a"])(l,s,r,!1,null,null,null);u.options.__file="node.vue";e["default"]=u.exports}}]);